class NewsResponseModel extends NewsResponseEntity {
  const NewsResponseModel({super.totalArticles, super.articles});

  factory NewsResponseModel.fromJson(dynamic json) {
    final List<ArticleModel> articles = [];
    if (json['articles'] != null) {
      json['articles'].forEach((v) {
        articles.add(ArticleModel.fromJson(v));
      });
    }
    return NewsResponseModel(
      totalArticles: json['totalArticles'],
      articles: articles,
    );
  }
}
